export const getCampaignQuestions = (country: string, year: number): CampaignQuestion[] => {
  const countryAliases: Record<string, string> = {
    'republic of ireland': 'ireland',
  };
  let countryKey = country.toLowerCase().trim();
  if (countryAliases[countryKey]) countryKey = countryAliases[countryKey];

  // Try exact match first
  if (campaignQuestions[countryKey] && campaignQuestions[countryKey][year]) {
    return campaignQuestions[countryKey][year];
  }
  
  // Try with quotes (for keys like 'united states')
  const quotedKey = `'${countryKey}'`;
  if (campaignQuestions[quotedKey] && campaignQuestions[quotedKey][year]) {
    return campaignQuestions[quotedKey][year];
  }
  
  // Try without quotes
  const unquotedKey = countryKey.replace(/['"]/g, '');
  if (campaignQuestions[unquotedKey] && campaignQuestions[unquotedKey][year]) {
    return campaignQuestions[unquotedKey][year];
  }
  
  return [];
};